// bundle-jsx.js — concatenates the JSX source files into a single bundle.jsx.
//
// Order matters:
//   1. json2.js          (JSON polyfill — must be first)
//   2. host.jsx          (declares COMMANDS + dispatch)
//   3. commands/*.jsx    (register on COMMANDS — order within this group is irrelevant)
//
// The bundle is what the panel loads via evalScript. It is gitignored.

import { readFileSync, writeFileSync, readdirSync, mkdirSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const jsxDir = resolve(__dirname, '..', 'jsx');
const commandsDir = resolve(jsxDir, 'commands');
const outFile = resolve(jsxDir, 'bundle.jsx');

const parts = [];

// 1. JSON polyfill
parts.push('// ====== json2.js (JSON polyfill) ======');
parts.push(readFileSync(resolve(jsxDir, 'json2.js'), 'utf8'));

// 2. host.jsx (dispatcher + COMMANDS declaration)
parts.push('\n// ====== host.jsx (dispatcher) ======');
parts.push(readFileSync(resolve(jsxDir, 'host.jsx'), 'utf8'));

// 3. All command files
const cmdFiles = readdirSync(commandsDir)
  .filter((f) => f.endsWith('.jsx'))
  .sort(); // alphabetical for determinism

for (const f of cmdFiles) {
  parts.push(`\n// ====== commands/${f} ======`);
  parts.push(readFileSync(resolve(commandsDir, f), 'utf8'));
}

// Write the bundle
const banner = [
  '// bundle.jsx — AUTO-GENERATED by panel/build/bundle-jsx.js',
  '// Do not edit this file directly. Edit the source files in panel/jsx/',
  '// and run: npm run build:jsx',
  '// Generated: ' + new Date().toISOString(),
  '',
].join('\n');

// ExtendScript's $.evalFile mis-decodes BOM-less UTF-8: any non-ASCII byte
// (e.g. an em-dash in a comment) makes it throw an uncatchable "EvalScript
// error.". Force the bundle to pure ASCII so it loads no matter how it's read.
// Keep tab/LF/CR; replace any other non-printable-ASCII char with '-'.
let bundle = banner + parts.join('\n\n');
const before = bundle.length;
bundle = bundle.replace(/[^\x09\x0A\x0D\x20-\x7E]/g, '-');
const replaced = [...(banner + parts.join('\n\n'))].filter(
  (c) => c.charCodeAt(0) > 0x7e || (c.charCodeAt(0) < 0x20 && !'\t\n\r'.includes(c)),
).length;

writeFileSync(outFile, bundle, 'ascii');
console.log(
  `[build:jsx] Bundled ${cmdFiles.length + 2} files → ${outFile}` +
  (replaced ? ` (sanitized ${replaced} non-ASCII char(s))` : ''),
);
void before;
